import{_ as e,o as i,c as r,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"银行卡绑定与审核","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/bank-card-binding.md","filePath":"zh-CN/deposit/bank-card-binding.md"}'),t={name:"deposit/bank-card-binding.md"};function n(h,a,o,d,p,s){return i(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="银行卡绑定与审核" tabindex="-1">银行卡绑定与审核 <a class="header-anchor" href="#银行卡绑定与审核" aria-label="Permalink to &quot;银行卡绑定与审核&quot;">​</a></h1><p>支持绑定的银行卡地区和银行、绑卡规则、信息填写、认证要求及常见问题解决。</p><h2 id="支持绑定的银行卡地区及银行" tabindex="-1">支持绑定的银行卡地区及银行 <a class="header-anchor" href="#支持绑定的银行卡地区及银行" aria-label="Permalink to &quot;支持绑定的银行卡地区及银行&quot;">​</a></h2><p>绑定银行卡时可选择以下地区，各地区支持的银行如下：</p><h3 id="香港地区-50-家" tabindex="-1">香港地区（50+ 家） <a class="header-anchor" href="#香港地区-50-家" aria-label="Permalink to &quot;香港地区（50+ 家）&quot;">​</a></h3><p>004 汇丰银行、012 中国银行（香港）、015 东亚银行、016 星展香港、018 中信国际、020 招商永隆、022 华侨银行、024 恒生银行、025 上海商业、027 交通 HK 分行、028 大众 HK、032 星展、035 华侨永亨、038 大有、039 集友、040 大新、041 创兴、043 南洋商业、052/185 星展、055 美国银行、061 大生、071 大华、072 工银亚洲、103 瑞银、128 富邦、152 澳新、221 建行亚洲、222 农业银行、238 招商 HK、241 永丰商业、258 华美、272 新加坡银行、274 王道商业、345 浦发 HK、353 民生银行（银证）、377 兴业、382 交通 HK、384 摩根士丹利亚洲、385 平安、387 众安、388 LIVI Bank、389 MOX Bank、390 WeLab Bank、391 富融、392 PAO Bank、393 Ant Bank、395 Airstar Bank、渣打银行、花旗银行、建行亚洲、其他银行</p><h3 id="美国地区-7-家" tabindex="-1">美国地区（7 家） <a class="header-anchor" href="#美国地区-7-家" aria-label="Permalink to &quot;美国地区（7 家）&quot;">​</a></h3><p>Bank of America、Cathay Bank、Chase Bank、Community Federal Savings Bank、East West Bank、HSBC Bank、其他银行</p><h3 id="马来西亚地区-8-家" tabindex="-1">马来西亚地区（8 家） <a class="header-anchor" href="#马来西亚地区-8-家" aria-label="Permalink to &quot;马来西亚地区（8 家）&quot;">​</a></h3><p>AmBank Berhad、CIMB Bank Berhad、Hong Leong Bank Berhad、Malayan Bank Berhad (Maybank)、OCBC Bank Berhad、Public Bank Berhad、RHB Bank Berhad、其他银行</p><h3 id="新加坡地区-7-家" tabindex="-1">新加坡地区（7 家） <a class="header-anchor" href="#新加坡地区-7-家" aria-label="Permalink to &quot;新加坡地区（7 家）&quot;">​</a></h3><p>CIMB Bank Berhad、DBS Bank Limited、HSBC Singapore、OCBC Singapore、Standard Chartered Bank、United Overseas Bank Limited (UOB)、其他银行</p><h3 id="澳大利亚地区-5-家" tabindex="-1">澳大利亚地区（5 家） <a class="header-anchor" href="#澳大利亚地区-5-家" aria-label="Permalink to &quot;澳大利亚地区（5 家）&quot;">​</a></h3><p>Bank of China Australia、Citigroup Pty Limited、Commonwealth Bank of Australia、HSBC Bank Australia、其他银行</p><h3 id="其他地区" tabindex="-1">其他地区 <a class="header-anchor" href="#其他地区" aria-label="Permalink to &quot;其他地区&quot;">​</a></h3><p>其他银行（需人工处理）</p><hr><h2 id="绑卡规则" tabindex="-1">绑卡规则 <a class="header-anchor" href="#绑卡规则" aria-label="Permalink to &quot;绑卡规则&quot;">​</a></h2><p>银行卡绑定最多两家不同银行（包含历史变动），同一家银行的卡数量不限制。</p><p>例如：3 张汇丰 + 2 张工银，这种组合是允许的。如果超出当前要求，需要先在 APP 内删除不用的银行卡，再申请绑定其他银行卡。</p><p>长桥支持香港卡、非香港卡入金。非香港地区银行卡目前仅支持 FATF 成员国家/地区的跨境银行转账，不支持大陆内地银行卡入金。请勿使用非 FATF 成员国家/地区银行卡直接转账至长桥账户，入金会被退回且退回手续费需自行承担。</p><h2 id="添加银行卡" tabindex="-1">添加银行卡 <a class="header-anchor" href="#添加银行卡" aria-label="Permalink to &quot;添加银行卡&quot;">​</a></h2><p>添加入口：</p><ul><li>长桥 App - 资产 - 银行卡 - 添加银行卡</li><li>存入资金 - 选择入金币种 - 选择银行卡页面底部「管理银行卡」</li><li>提取资金 - 选择「提取至右侧更多」- 底部「管理我的银行卡」</li></ul><h3 id="填写银行卡信息" tabindex="-1">填写银行卡信息 <a class="header-anchor" href="#填写银行卡信息" aria-label="Permalink to &quot;填写银行卡信息&quot;">​</a></h3><ul><li>银行账户地区：选择银行卡所属地区（香港、美国、新加坡等）</li><li>卡所属银行：选择对应银行名称。香港地区银行卡需确认银行代码，如中国银行存在多个银行代码（012、014、338、070 等），需咨询开户行工作人员，或查看银行开户单账户号码前的分行号；选错分行会影响出入金</li><li>银行账户姓名：下拉选择，姓名排序需与银行端一致（如 ZHANG SAN 或 SAN ZHANG），选错会导致入金失败</li><li>银行账号：填写银行卡账户信息。部分银行存在综合账户卡号，不同币种对应卡号不同，入金前需提前确认</li><li>账户类型：根据银行卡号在银行端对应的账户类型选择 <ul><li>港元账户：出入金仅支持港元</li><li>美元账户：出入金仅支持美元</li><li>综合账户：出入金支持美元和港元。绑定卡后如在入金页面看不到该卡，需检查账户类型与入金币种是否匹配，可在「资产 → 银行卡」中修改</li></ul></li><li>FPS 账号：选填，填写后提交出入金申请时可更快审核确认</li><li>银行卡证明：需同时包含客户姓名和银行账号的银行资料，如银行卡、银行结单、开户证明等。认证资料错误会影响出金流程，可能导致出金失败并产生银行费用</li></ul><h2 id="银行卡授权状态" tabindex="-1">银行卡授权状态 <a class="header-anchor" href="#银行卡授权状态" aria-label="Permalink to &quot;银行卡授权状态&quot;">​</a></h2><p>银行卡可能处于以下状态：eDDA 已授权、银证已授权、审核中。</p><p>处于这些状态下，无法直接删除银行卡，也无法直接修改银行账户姓名和银行卡号信息；如需修改，请联系客服进行人工处理。</p><h2 id="银行卡认证-出金前" tabindex="-1">银行卡认证（出金前） <a class="header-anchor" href="#银行卡认证-出金前" aria-label="Permalink to &quot;银行卡认证（出金前）&quot;">​</a></h2><p>首次出金前，银行卡需完成认证。在提取资金页面如提示银行卡未认证，需点击「立即认证」上传银行卡认证资料。</p><p>认证资料必须同时包含客户姓名和银行账号，可选择以下任意一种：</p><ul><li>银行月结账单</li><li>银行卡正面（需包含姓名，部分银行卡正面无姓名的需提供带姓名的实体卡截图）</li><li>开户成功的回执</li></ul><p>支持最多上传 3 张图，提交后预计 1-3 个工作日处理完毕。请确保认证资料与长桥账户同名。</p><h2 id="开户中绑卡" tabindex="-1">开户中绑卡 <a class="header-anchor" href="#开户中绑卡" aria-label="Permalink to &quot;开户中绑卡&quot;">​</a></h2><p>开户过程中只允许绑定一张银行卡，若有多次绑卡行为，默认为编辑更新银行卡信息。</p><h2 id="aml-风控审核" tabindex="-1">AML 风控审核 <a class="header-anchor" href="#aml-风控审核" aria-label="Permalink to &quot;AML 风控审核&quot;">​</a></h2><p>超过两家银行的银行卡绑定会触发风控审核。如银行卡绑定提交后被拒绝，可能是因为绑定银行已超过 2 家限制；若系统提示重复，说明该卡已存在，无需重复添加，请检查「资产 → 银行卡」中是否已有该卡及账户类型是否匹配。</p><p>如有在途入金需要绑卡操作等特殊情况，请联系客服协助处理。</p><h2 id="删除银行卡" tabindex="-1">删除银行卡 <a class="header-anchor" href="#删除银行卡" aria-label="Permalink to &quot;删除银行卡&quot;">​</a></h2><p>删除路径：长桥 App - 资产 - 银行卡 - 选择具体银行卡 - 删除。</p><p>如银行卡已完成 eDDA 授权、银证授权、入金已见证等，不支持直接删除，必须先解除授权后才能删除。</p><p>如入金申请被驳回并提示银行卡信息填写错误，驳回并非退款——在「存入资金 → 入金记录」点击该记录，查看错误字段，点击「立即修改」更正银行卡信息后重新提交。</p><h2 id="姓名多音字问题" tabindex="-1">姓名多音字问题 <a class="header-anchor" href="#姓名多音字问题" aria-label="Permalink to &quot;姓名多音字问题&quot;">​</a></h2><p>如因姓名多音字导致银行卡绑定信息不一致，请联系客服并提供可证明姓名正确读音的证件（如港澳通行证、护照、银行结单等），协助修改为正确姓名。</p><h2 id="信用卡限制" tabindex="-1">信用卡限制 <a class="header-anchor" href="#信用卡限制" aria-label="Permalink to &quot;信用卡限制&quot;">​</a></h2><p>长桥不支持信用卡作为入金方式，也不支持绑定信用卡：</p><ul><li>不支持使用信用卡进行开户入金验证</li><li>如通过信用卡汇款入金，资金到账后将被原路退款，退款处理约 14 个工作日，退款手续费由客户承担</li></ul>',48)])])}const k=e(t,[["render",n]]);export{c as __pageData,k as default};
